function pickContext(state: InterventionsState, modal: ActiveModalLike) {
  return {
    request: state.requests.find(item => item.id === modal.entityId) || state.requests[0],
    order: state.orders.find(item => item.id === modal.entityId) || state.orders[0],
    staff: state.staff.find(item => item.id === modal.entityId) || state.staff[0],
    equipment: state.equipment.find(item => item.id === modal.entityId) || state.equipment[0],
    invoice: state.invoices.find(item => item.id === modal.entityId) || state.invoices[0],
    route: state.routes.find(item => item.id === modal.entityId) || state.routes[0],
  }
}
function mad(value?: number) { return new Intl.NumberFormat('fr-MA', { style: 'currency', currency: 'MAD' }).format(value || 0) }

function Pill({ children, tone = 'slate' }: { children: React.ReactNode; tone?: 'slate' | 'cyan' | 'emerald' | 'amber' | 'rose' | 'violet' }) {
  const tones = { slate: 'border-slate-200 bg-slate-50 text-slate-700', cyan: 'border-cyan-200 bg-cyan-50 text-cyan-800', emerald: 'border-emerald-200 bg-emerald-50 text-emerald-800', amber: 'border-amber-200 bg-amber-50 text-amber-800', rose: 'border-rose-200 bg-rose-50 text-rose-800', violet: 'border-violet-200 bg-violet-50 text-violet-800' }
  return <span className={`inline-flex rounded-full border px-3 py-1 text-[11px] font-black ${tones[tone]}`}>{children}</span>
}
function Metric({ label, value, detail }: { label: string; value: string; detail: string }) { return <div className="rounded-[22px] border border-slate-200 bg-white p-4 shadow-sm"><p className="text-[10px] font-black uppercase tracking-[0.22em] text-slate-400">{label}</p><p className="mt-1 text-xl font-black text-slate-950">{value}</p><p className="mt-1 text-xs font-bold text-slate-500">{detail}</p></div> }
function SelectorGroup({ selector, active, onChange, compact = false }: { selector: ModalSelector; active: string; onChange: (value: string) => void; compact?: boolean }) { return <div className={`rounded-[26px] border border-slate-200 bg-white p-${compact ? '3' : '4'} shadow-sm`}><p className="text-[10px] font-black uppercase tracking-[0.24em] text-slate-400">{selector.title}</p><div className="mt-3 grid gap-2">{selector.options.map(option => <button key={option} type="button" onClick={() => onChange(option)} className={`rounded-2xl border px-3 py-2 text-left text-sm font-extrabold transition ${active === option ? 'border-cyan-300 bg-cyan-50 text-cyan-950 shadow-sm' : 'border-slate-200 bg-white text-slate-700 hover:bg-slate-50'}`}>{option}</button>)}</div></div> }
function Field({ field, selections }: { field: ModalField; selections: string[] }) {
  const base = 'mt-2 w-full rounded-2xl border border-slate-200 bg-white px-4 py-3 text-sm font-bold text-slate-900 outline-none focus:border-cyan-400 focus:ring-4 focus:ring-cyan-100'
  return <label className="rounded-[24px] border border-slate-200 bg-slate-50 p-4"><span className="text-[10px] font-black uppercase tracking-[0.22em] text-slate-500">{field.label}{field.required ? ' *' : ''}</span>{field.kind === 'textarea' ? <textarea rows={3} className={base} placeholder={field.placeholder || field.label} /> : field.kind === 'select' ? <select className={base}>{(field.options || selections).map(option => <option key={option}>{option}</option>)}</select> : field.kind === 'toggle' ? <div className="mt-3 flex gap-2"><Pill tone="emerald">Oui</Pill><Pill>Non</Pill><Pill tone="amber">Selon rôle</Pill></div> : <input className={base} type={field.kind === 'money' || field.kind === 'number' ? 'number' : field.kind} placeholder={field.placeholder || field.label} />}</label>
}
function EvidencePanel({ design }: { design: ModalDesign }) { return <div className="rounded-[28px] border border-emerald-200 bg-emerald-50 p-5"><p className="text-[10px] font-black uppercase tracking-[0.24em] text-emerald-700">Écritures / audit réels</p><div className="mt-3 space-y-2">{design.downstream.map(item => <p key={item} className="text-sm font-bold text-emerald-950">✓ {item}</p>)}</div><div className="mt-4 rounded-2xl bg-white/70 p-3 text-xs font-black text-emerald-900">{design.writePath}</div></div> }
function ControlList({ title, items, tone = 'cyan' }: { title: string; items: string[]; tone?: 'cyan' | 'amber' | 'rose' | 'emerald' }) { return <div className="rounded-[28px] border border-slate-200 bg-white p-5 shadow-sm"><p className="text-[10px] font-black uppercase tracking-[0.24em] text-slate-400">{title}</p><div className="mt-3 flex flex-wrap gap-2">{items.map(item => <Pill key={item} tone={tone}>{item}</Pill>)}</div></div> }

function IntakeWizard({ design, selections, setSelection }: any) { return <div className="grid gap-5 xl:grid-cols-[320px_1fr_360px]"><div className="space-y-4"><SelectorGroup selector={design.selectors[0]} active={selections[0]} onChange={(v) => setSelection(0, v)} /><div className="rounded-[30px] border border-cyan-200 bg-cyan-50 p-5"><p className="text-xs font-black text-cyan-800">Étapes intake</p>{['1. Identité', '2. Famille', '3. Adresse', '4. Service', '5. Documents'].map(step => <div key={step} className="mt-3 rounded-2xl bg-white px-4 py-3 text-sm font-black text-slate-800">{step}</div>)}</div></div><div className="rounded-[34px] border border-slate-200 bg-white p-5 shadow-md"><h3 className="text-2xl font-black text-slate-950">Fiche création demande</h3><div className="mt-5 grid gap-3 md:grid-cols-2">{design.fields.map((field: ModalField) => <Field key={field.label} field={field} selections={selections}/>)}</div></div><div className="space-y-4"><SelectorGroup selector={design.selectors[1]} active={selections[1]} onChange={(v) => setSelection(1, v)} /><SelectorGroup selector={design.selectors[2]} active={selections[2]} onChange={(v) => setSelection(2, v)} /><EvidencePanel design={design}/></div></div> }
function TriageBoard({ design, selections, setSelection }: any) { return <div className="grid gap-5 xl:grid-cols-[1.1fr_.9fr]"><div className="rounded-[34px] border border-slate-200 bg-white p-5 shadow-md"><h3 className="text-2xl font-black">Matrice décision triage</h3><div className="mt-5 grid gap-3 md:grid-cols-2">{design.selectors.map((s: ModalSelector, i: number) => <SelectorGroup key={s.title} selector={s} active={selections[i]} onChange={(v) => setSelection(i, v)} compact />)}</div><div className="mt-5 grid gap-3 md:grid-cols-2">{design.fields.map((field: ModalField) => <Field key={field.label} field={field} selections={selections}/>)}</div></div><div className="space-y-4"><ControlList title="Règles triage" items={design.controls} tone="amber"/><div className="rounded-[30px] border border-rose-200 bg-rose-50 p-5"><p className="text-xs font-black uppercase tracking-[0.2em] text-rose-800">Escalade possible</p><p className="mt-3 text-sm font-bold text-rose-950">Si risque critique ou document bloquant, le bouton d’escalade écrit directement un audit et alimente la file superviseur médical.</p></div><EvidencePanel design={design}/></div></div> }
function FinanceLedger({ design, selections, setSelection }: any) { return <div className="grid gap-5 xl:grid-cols-[.9fr_1.2fr_.9fr]"><div className="space-y-4"><Metric label="Montant cible" value={mad(design.amountHint || 450)} detail="MAD / dirham"/><SelectorGroup selector={design.selectors[0]} active={selections[0]} onChange={(v) => setSelection(0, v)} /><SelectorGroup selector={design.selectors[1]} active={selections[1]} onChange={(v) => setSelection(1, v)} /></div><div className="rounded-[34px] border border-slate-200 bg-white p-5 shadow-md"><h3 className="text-2xl font-black">Grand livre opérationnel MAD</h3><div className="mt-4 rounded-[26px] border border-slate-200 bg-slate-50 p-4"><div className="grid grid-cols-3 gap-3 text-center"><Metric label="Base" value={mad(design.amountHint || 450)} detail="service"/><Metric label="Restant" value={mad(0)} detail="à payer"/><Metric label="Audit" value="OK" detail={design.audit}/></div></div><div className="mt-5 grid gap-3 md:grid-cols-2">{design.fields.map((field: ModalField) => <Field key={field.label} field={field} selections={selections}/>)}</div></div><div className="space-y-4"><SelectorGroup selector={design.selectors[2]} active={selections[2]} onChange={(v) => setSelection(2, v)} /><ControlList title="Contrôles finance" items={design.controls} tone="emerald"/><EvidencePanel design={design}/></div></div> }
function StaffMatcher({ design, selections, setSelection, state }: any) { const staff = state.staff.slice(0, 4); return <div className="grid gap-5 xl:grid-cols-[360px_1fr]"><div className="space-y-4">{design.selectors.map((s: ModalSelector, i: number) => <SelectorGroup key={s.title} selector={s} active={selections[i]} onChange={(v) => setSelection(i, v)} />)}</div><div className="space-y-4"><div className="rounded-[34px] border border-slate-200 bg-white p-5 shadow-md"><h3 className="text-2xl font-black">Matching certifié et disponibilité</h3><div className="mt-5 grid gap-3 md:grid-cols-2">{staff.map((member: any, idx: number) => <div key={member.id || idx} className="rounded-[24px] border border-slate-200 bg-slate-50 p-4"><div className="flex items-start justify-between"><div><p className="font-black text-slate-950">{member.fullName}</p><p className="text-sm font-bold text-slate-500">{member.role} • {member.city}/{member.zone}</p></div><Pill tone={member.availability === 'Disponible' ? 'emerald' : 'amber'}>{member.availability}</Pill></div><div className="mt-3 flex flex-wrap gap-2"><Pill tone="cyan">score {92 - idx * 7}%</Pill><Pill>charge {member.workload}</Pill><Pill tone={member.emergencyEligible ? 'emerald' : 'slate'}>{member.emergencyEligible ? 'urgence OK' : 'standard'}</Pill></div></div>)}</div><div className="mt-5 grid gap-3 md:grid-cols-2">{design.fields.map((field: ModalField) => <Field key={field.label} field={field} selections={selections}/>)}</div></div><div className="grid gap-4 md:grid-cols-2"><ControlList title="Gates staff" items={design.controls} tone="cyan"/><EvidencePanel design={design}/></div></div></div> }
function CalendarScheduler({ design, selections, setSelection }: any) { const slots = ['08:00', '10:00', '12:00', '14:00', '16:00', '18:00']; return <div className="grid gap-5 xl:grid-cols-[1fr_420px]"><div className="rounded-[34px] border border-slate-200 bg-white p-5 shadow-md"><h3 className="text-2xl font-black">Planning visuel et conflits</h3><div className="mt-5 grid gap-3 md:grid-cols-3">{slots.map((slot, idx) => <button key={slot} className={`rounded-[24px] border p-5 text-left ${idx === 2 ? 'border-amber-300 bg-amber-50' : 'border-slate-200 bg-slate-50'}`}><p className="text-2xl font-black">{slot}</p><p className="text-xs font-bold text-slate-500">{idx === 2 ? 'SLA serré' : 'créneau disponible'}</p></button>)}</div><div className="mt-5 grid gap-3 md:grid-cols-2">{design.fields.map((field: ModalField) => <Field key={field.label} field={field} selections={selections}/>)}</div></div><div className="space-y-4">{design.selectors.map((s: ModalSelector, i: number) => <SelectorGroup key={s.title} selector={s} active={selections[i]} onChange={(v) => setSelection(i, v)} />)}<EvidencePanel design={design}/></div></div> }
function DispatchProof({ design, selections, setSelection }: any) { return <div className="grid gap-5 xl:grid-cols-[.85fr_1.15fr_1fr]"><div className="space-y-4">{design.selectors.map((s: ModalSelector, i: number) => <SelectorGroup key={s.title} selector={s} active={selections[i]} onChange={(v) => setSelection(i, v)} />)}</div><div className="rounded-[34px] border border-slate-200 bg-white p-5 shadow-md"><h3 className="text-2xl font-black">Preuve terrain et horodatage</h3><div className="mt-5 grid gap-3 md:grid-cols-2">{design.fields.map((field: ModalField) => <Field key={field.label} field={field} selections={selections}/>)}</div></div><div className="space-y-4"><ControlList title="Checklist preuve" items={design.controls} tone="cyan"/><EvidencePanel design={design}/></div></div> }
function CompletionReport({ design, selections, setSelection }: any) { return <div className="grid gap-5 xl:grid-cols-[1.2fr_.8fr]"><div className="rounded-[34px] border border-slate-200 bg-white p-5 shadow-md"><h3 className="text-2xl font-black">Rapport de clôture obligatoire</h3><div className="mt-5 grid gap-3 md:grid-cols-2">{design.fields.map((field: ModalField) => <Field key={field.label} field={field} selections={selections}/>)}</div><div className="mt-5 rounded-[26px] border border-emerald-200 bg-emerald-50 p-4"><p className="font-black text-emerald-950">La clôture écrit rapport + statut + facturation + audit. Pas de clôture silencieuse.</p></div></div><div className="space-y-4">{design.selectors.map((s: ModalSelector, i: number) => <SelectorGroup key={s.title} selector={s} active={selections[i]} onChange={(v) => setSelection(i, v)} />)}<EvidencePanel design={design}/></div></div> }
function RoutePlanner({ design, selections, setSelection }: any) { return <div className="grid gap-5 xl:grid-cols-[1fr_1fr]"><div className="rounded-[34px] border border-slate-200 bg-white p-5 shadow-md"><h3 className="text-2xl font-black">Carte tournée / arrêts</h3><div className="mt-4 min-h-[280px] rounded-[30px] border border-cyan-100 bg-[radial-gradient(circle_at_20%_25%,#cffafe_0_7%,transparent_8%),radial-gradient(circle_at_70%_45%,#bfdbfe_0_8%,transparent_9%),linear-gradient(135deg,#fff,#f8fafc)] p-5"><div className="space-y-3">{['Stop 01', 'Stop 02', 'Stop 03'].map((stop, idx) => <div key={stop} className="rounded-2xl border border-white bg-white/80 px-4 py-3 font-black shadow-sm">{stop} • {idx === 0 ? 'Urgence' : 'Planifié'}</div>)}</div></div><div className="mt-5 grid gap-3 md:grid-cols-2">{design.fields.map((field: ModalField) => <Field key={field.label} field={field} selections={selections}/>)}</div></div><div className="space-y-4">{design.selectors.map((s: ModalSelector, i: number) => <SelectorGroup key={s.title} selector={s} active={selections[i]} onChange={(v) => setSelection(i, v)} />)}<EvidencePanel design={design}/></div></div> }
function EquipmentLogistics({ design, selections, setSelection }: any) { return <div className="grid gap-5 xl:grid-cols-[.9fr_1.1fr_.9fr]"><div className="space-y-4"><Metric label="Asset" value="Traçable" detail="mouvement obligatoire"/>{design.selectors.slice(0,1).map((s: ModalSelector, i: number) => <SelectorGroup key={s.title} selector={s} active={selections[i]} onChange={(v) => setSelection(i, v)} />)}</div><div className="rounded-[34px] border border-slate-200 bg-white p-5 shadow-md"><h3 className="text-2xl font-black">Flux logistique équipement</h3><div className="mt-4 grid grid-cols-3 gap-3 text-center"><div className="rounded-2xl bg-slate-50 p-4 font-black">Dépôt</div><div className="rounded-2xl bg-cyan-50 p-4 font-black">Transit</div><div className="rounded-2xl bg-emerald-50 p-4 font-black">Patient</div></div><div className="mt-5 grid gap-3 md:grid-cols-2">{design.fields.map((field: ModalField) => <Field key={field.label} field={field} selections={selections}/>)}</div></div><div className="space-y-4">{design.selectors.slice(1).map((s: ModalSelector, i: number) => <SelectorGroup key={s.title} selector={s} active={selections[i+1]} onChange={(v) => setSelection(i+1, v)} />)}<EvidencePanel design={design}/></div></div> }
function SettingsMatrix({ design, selections, setSelection }: any) { return <div className="grid gap-5 xl:grid-cols-[360px_1fr]"><div className="space-y-4">{design.selectors.map((s: ModalSelector, i: number) => <SelectorGroup key={s.title} selector={s} active={selections[i]} onChange={(v) => setSelection(i, v)} />)}</div><div className="rounded-[34px] border border-slate-200 bg-white p-5 shadow-md"><h3 className="text-2xl font-black">Matrice configuration production</h3><div className="mt-5 grid gap-3 md:grid-cols-2">{design.fields.map((field: ModalField) => <Field key={field.label} field={field} selections={selections}/>)}</div><div className="mt-5 grid gap-4 md:grid-cols-2"><ControlList title="Contrôles" items={design.controls} tone="cyan"/><EvidencePanel design={design}/></div></div></div> }
function PatientCare({ design, selections, setSelection }: any) { return <div className="grid gap-5 xl:grid-cols-[1fr_.9fr]"><div className="rounded-[34px] border border-slate-200 bg-white p-5 shadow-md"><h3 className="text-2xl font-black">Dossier opérationnel home-care</h3><div className="mt-5 grid gap-3 md:grid-cols-2">{design.fields.map((field: ModalField) => <Field key={field.label} field={field} selections={selections}/>)}</div></div><div className="space-y-4">{design.selectors.map((s: ModalSelector, i: number) => <SelectorGroup key={s.title} selector={s} active={selections[i]} onChange={(v) => setSelection(i, v)} />)}<ControlList title="Limites opérationnelles" items={design.controls} tone="emerald"/><EvidencePanel design={design}/></div></div> }
function ReportExporter({ design, selections, setSelection }: any) { return <div className="grid gap-5 xl:grid-cols-[1fr_1fr]"><div className="rounded-[34px] border border-slate-200 bg-white p-5 shadow-md"><h3 className="text-2xl font-black">Générateur rapport / impression</h3><div className="mt-5 grid gap-3 md:grid-cols-2">{design.fields.map((field: ModalField) => <Field key={field.label} field={field} selections={selections}/>)}</div></div><div className="space-y-4">{design.selectors.map((s: ModalSelector, i: number) => <SelectorGroup key={s.title} selector={s} active={selections[i]} onChange={(v) => setSelection(i, v)} />)}<div className="rounded-[28px] border border-cyan-200 bg-cyan-50 p-5"><p className="font-black text-cyan-950">Aperçu document propre bureau/terrain — aucune exportation de données fictives.</p></div><EvidencePanel design={design}/></div></div> }
function IncidentWarRoom({ design, selections, setSelection }: any) { return <div className="grid gap-5 xl:grid-cols-[.85fr_1.15fr_.85fr]"><div className="space-y-4">{design.selectors.slice(0,2).map((s: ModalSelector, i: number) => <SelectorGroup key={s.title} selector={s} active={selections[i]} onChange={(v) => setSelection(i, v)} />)}</div><div className="rounded-[34px] border border-rose-200 bg-white p-5 shadow-md"><h3 className="text-2xl font-black text-rose-950">War room incident</h3><div className="mt-5 grid gap-3 md:grid-cols-2">{design.fields.map((field: ModalField) => <Field key={field.label} field={field} selections={selections}/>)}</div></div><div className="space-y-4"><SelectorGroup selector={design.selectors[2]} active={selections[2]} onChange={(v) => setSelection(2, v)} /><ControlList title="Mesures immédiates" items={design.controls} tone="rose"/><EvidencePanel design={design}/></div></div> }

function PurposeBody({ design, selections, setSelection, state }: { design: ModalDesign; selections: string[]; setSelection: (index: number, value: string) => void; state: InterventionsState }) {
  if (design.mode === 'intakeWizard') return <IntakeWizard design={design} selections={selections} setSelection={setSelection}/>
  if (design.mode === 'triageBoard') return <TriageBoard design={design} selections={selections} setSelection={setSelection}/>
  if (design.mode === 'conversionDesk' || design.mode === 'orderFactory') return <IntakeWizard design={design} selections={selections} setSelection={setSelection}/>
  if (design.mode === 'financeLedger') return <FinanceLedger design={design} selections={selections} setSelection={setSelection}/>
  if (design.mode === 'staffMatcher') return <StaffMatcher design={design} selections={selections} setSelection={setSelection} state={state}/>
  if (design.mode === 'calendarScheduler') return <CalendarScheduler design={design} selections={selections} setSelection={setSelection}/>
  if (design.mode === 'dispatchProof' || design.mode === 'arrivalGate' || design.mode === 'startChecklist') return <DispatchProof design={design} selections={selections} setSelection={setSelection}/>
  if (design.mode === 'completionReport') return <CompletionReport design={design} selections={selections} setSelection={setSelection}/>
  if (design.mode === 'cancellationControl') return <TriageBoard design={design} selections={selections} setSelection={setSelection}/>
  if (design.mode === 'routePlanner' || design.mode === 'mapCommand') return <RoutePlanner design={design} selections={selections} setSelection={setSelection}/>
  if (design.mode === 'equipmentLogistics') return <EquipmentLogistics design={design} selections={selections} setSelection={setSelection}/>
  if (design.mode === 'incidentWarRoom') return <IncidentWarRoom design={design} selections={selections} setSelection={setSelection}/>
  if (design.mode === 'staffOps') return <StaffMatcher design={design} selections={selections} setSelection={setSelection} state={state}/>
  if (design.mode === 'patientCare') return <PatientCare design={design} selections={selections} setSelection={setSelection}/>
  if (design.mode === 'settingsMatrix') return <SettingsMatrix design={design} selections={selections} setSelection={setSelection}/>
  if (design.mode === 'reportExporter') return <ReportExporter design={design} selections={selections} setSelection={setSelection}/>
  if (design.mode === 'duplicateResolver') return <TriageBoard design={design} selections={selections} setSelection={setSelection}/>
  return <SettingsMatrix design={design} selections={selections} setSelection={setSelection}/>
}

function Success({ design, onClose }: { design: ModalDesign; onClose: () => void }) { return <div className="rounded-[36px] border border-emerald-200 bg-emerald-50 p-8 text-emerald-950"><p className="text-xs font-black uppercase tracking-[0.24em] text-emerald-700">Action exécutée</p><h3 className="mt-2 text-3xl font-black">{design.primary}</h3><p className="mt-3 max-w-3xl font-semibold leading-7">Workflow écrit sur {design.writePath}. Audit: {design.audit}. Le workspace peut être revalidé sans bouton générique.</p><button onClick={onClose} className="mt-6 rounded-2xl border border-emerald-300 bg-white px-5 py-3 text-sm font-black text-emerald-900">Fermer</button></div> }

export default function Phase12ActionModal({ modal, onClose, execute, state }: { modal: ActiveModalLike; onClose: () => void; execute: ExecuteFn; state: InterventionsState }) {
  const design = MODAL_DESIGNS[modal.key]
  const blueprint = MODAL_BLUEPRINTS[modal.key]
  const [busy, setBusy] = useState(false)
  const [saved, setSaved] = useState(false)
  const [selections, setSelections] = useState<string[]>(() => design.selectors.map(s => s.options[0]))
  const ctx = useMemo(() => pickContext(state, modal), [state, modal])
  if (!design || !blueprint) return null
  function setSelection(index: number, value: string) { setSelections(current => current.map((item, idx) => idx === index ? value : item)) }
  async function submit(label: string) {
    setBusy(true)
    const entityId = modal.entityId || ctx.order?.id || ctx.request?.id
    const selectedRole = selections.find(item => COMMON_ROLES.includes(item as any)) || 'Infirmier'
    const selectedCity = selections.find(item => COMMON_CITIES.includes(item)) || ctx.order?.city || ctx.request?.city || 'Rabat'
    const selectedAvailability = selections.find(item => STAFF_AVAILABILITY.includes(item)) || 'Disponible'
    const staffCreateValues = modal.key === 'StaffProfileModal' ? {
      fullName: `Nouveau ${selectedRole} ${new Date().toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' })}`,
      role: selectedRole,
      phone: '+212 600 00 00 00',
      city: selectedCity,
      zone: ctx.order?.zone || ctx.request?.zone || 'Centre',
      availability: selectedAvailability === 'Urgence seulement' ? 'Urgence seulement' : selectedAvailability.startsWith('Indisponible') ? 'Indisponible' : 'Disponible',
      workload: 0,
      certifications: ['Créé depuis Interventions OS', selectedRole],
      emergencyEligible: selectedAvailability !== 'Indisponible',
      skills: [selectedRole, selections[0]].filter(Boolean),
    } : {}
    await execute(design.action || blueprint.action, entityId, modal.entityType || 'intervention', {
      phase: 'phase12_corrected_unique_purpose_modals', modalKey: modal.key, actionLabel: label, selectedOptions: selections,
      summary: `${design.title} — ${label} — ${selections.join(' / ')}`, auditEvent: design.audit,
      riskLevel: (blueprint.suggestedRisk || ctx.order?.riskLevel || ctx.request?.riskLevel || 'Modéré') as RiskLevel,
      amountMad: ctx.invoice?.amountMad || ctx.order?.amountMad || ctx.request?.estimatedAmountMad || design.amountHint || 450,
      staffIds: ctx.staff?.id ? [ctx.staff.id] : state.staff.slice(0, 1).map(item => item.id),
      locationId: state.locations[0]?.id, city: selectedCity, zone: ctx.order?.zone || ctx.request?.zone || 'Agdal', workflowWriteTarget: design.writePath,
      ...staffCreateValues,
    })
    try { await fetch('/api/interventions/modal-execution', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ modalKey: modal.key, action: design.action, actionLabel: label, entityId, entityType: modal.entityType || 'intervention', selectedOptions: selections, auditEvent: design.audit, writePath: design.writePath }) }) } catch {}
    setSaved(true); setBusy(false)
  }
  const secondaryButtons = [design.secondary, design.tertiary].filter(Boolean) as string[]
  return <div className="fixed inset-0 z-[1300] flex items-center justify-center bg-slate-950/45 p-3 backdrop-blur-xl"><div className="max-h-[94vh] w-[min(1540px,100%)] overflow-auto rounded-[38px] border border-slate-200 bg-white shadow-[0_42px_140px_rgba(15,23,42,.30)]"><div className="sticky top-0 z-20 border-b border-slate-200 bg-white/95 p-5 backdrop-blur md:p-7"><div className="flex flex-col gap-4 xl:flex-row xl:items-start xl:justify-between"><div className="flex gap-4"><div className="flex h-16 w-16 items-center justify-center rounded-[24px] border border-cyan-200 bg-cyan-50 text-3xl">{design.icon}</div><div><p className="text-[10px] font-black uppercase tracking-[0.34em] text-cyan-700">Phase 12 corrigée • {design.eyebrow} • {modal.key}</p><h2 className="mt-2 text-3xl font-black tracking-tight text-slate-950 md:text-5xl">{design.title}</h2><p className="mt-2 max-w-5xl text-sm font-semibold leading-6 text-slate-600 md:text-base">{design.subtitle}</p></div></div><button onClick={onClose} className="rounded-2xl border border-slate-200 bg-white px-4 py-3 text-sm font-black text-slate-700">Fermer</button></div><div className="mt-5 grid gap-3 md:grid-cols-4"><Metric label="Action" value={design.action} detail="workflow réel"/><Metric label="Audit" value={design.audit} detail="évènement dédié"/><Metric label="Contexte" value="Maroc / MAD" detail="+212 • villes Maroc"/><Metric label="Cible" value={modal.entityType || 'workflow'} detail={modal.entityId || 'sélection contextuelle'}/></div></div><div className="p-5 md:p-7">{saved ? <Success design={design} onClose={onClose}/> : <><PurposeBody design={design} selections={selections} setSelection={setSelection} state={state}/><div className="mt-7 rounded-[30px] border border-slate-200 bg-slate-50 p-5"><div className="flex flex-col gap-4 xl:flex-row xl:items-center xl:justify-between"><div><p className="text-xs font-black uppercase tracking-[0.24em] text-slate-500">Footer pertinent uniquement</p><p className="mt-1 max-w-2xl text-sm font-semibold text-slate-600">Boutons spécifiques à {design.title}. Aucun bouton de footer générique partagé entre actions incompatibles.</p></div><div className="flex flex-wrap justify-end gap-2"><button onClick={onClose} className="rounded-2xl border border-slate-200 bg-white px-4 py-3 text-sm font-black text-slate-700">Fermer sans écrire</button>{secondaryButtons.map(label => <button key={label} onClick={() => submit(label)} disabled={busy} className="rounded-2xl border border-slate-200 bg-white px-4 py-3 text-sm font-black text-slate-800 disabled:opacity-50">{label}</button>)}{design.danger && <button onClick={() => submit(design.danger || 'Action critique')} disabled={busy} className="rounded-2xl border border-rose-300 bg-rose-50 px-4 py-3 text-sm font-black text-rose-800 disabled:opacity-50">{design.danger}</button>}<button onClick={() => submit(design.primary)} disabled={busy} className="rounded-2xl border border-cyan-700 bg-cyan-700 px-5 py-3 text-sm font-black text-white shadow-lg shadow-cyan-900/10 disabled:opacity-50">{busy ? 'Synchronisation...' : design.primary}</button></div></div></div></>}</div></div></div>
}
